```bash
cp ./llvm/lib/Transforms/Utils/LoopUtils.cpp ./llvm/lib/Transforms/Utils/LoopUtils.cpp.backup
```

Now edit the file to add the check. I'll use sed to insert after the line `Loop *L = PreOrderWorklist.pop_back_val();`.

```bash
sed -i '1790,1820p' ./llvm/lib/Transforms/Utils/LoopUtils.cpp
```

Actually, let me write a more precise edit. I'll create a patch file.

```bash
cat <<'EOF' > /tmp/fix.patch
--- a/llvm/lib/Transforms/Utils/LoopUtils.cpp
+++ b/llvm/lib/Transforms/Utils/LoopUtils.cpp
@@ -1803,6 +1803,9 @@ void llvm::appendReversedLoopsToWorklist(
     PreOrderWorklist.push_back(RootL);
     do {
       Loop *L = PreOrderWorklist.pop_back_val();
+      // Skip invalid loops. They may have been destroyed by previous passes.
+      if (L->isInvalid())
+        continue;
       PreOrderWorklist.append(L->begin(), L->end());
       PreOrderLoops.push_back(L);
     } while (!PreOrderWorklist.empty());
EOF
```

